import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { getPath } from "../../api";

export default function PathPage() {
  const navigate = useNavigate();
  const sessionId = localStorage.getItem("session_id");
  const [path, setPath] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const load = async () => {
      try {
        const res = await getPath(sessionId, 6);
        setPath(res.data.path);
      } catch (e) {
        setError("Could not load your learning path.");
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const levelColor = (step) => {
    const colors = [
      "#1D9E75",
      "#378ADD",
      "#7F77DD",
      "#EF9F27",
      "#E24B4A",
      "#1D9E75",
    ];
    return colors[(step - 1) % colors.length];
  };

  return (
    <div style={s.page}>
      {/* Header */}
      <div style={s.header}>
        <div>
          <h1 style={s.title}>My Learning Path</h1>
          <p style={s.sub}>
            Your personalised 6-step roadmap generated by the RL engine
          </p>
        </div>
        <button style={s.learnBtn} onClick={() => navigate("/dashboard/learn")}>
          Start Learning →
        </button>
      </div>

      {loading ? (
        <div style={s.loadWrap}>
          <div style={s.spinner} />
          <p style={s.loadText}>Generating your path…</p>
        </div>
      ) : error ? (
        <div style={s.errorBox}>{error}</div>
      ) : (
        <div style={s.pathWrap}>
          {path.map((item, i) => {
            const color = levelColor(item.step);
            const isLast = i === path.length - 1;
            const parts = item.concept.match(/^(.+?)\s+L(\d+)$/);
            const name = parts ? parts[1] : item.concept;
            const level = parts ? parts[2] : "?";

            return (
              <div key={i} style={s.stepRow}>
                {/* Left — step number + connector */}
                <div style={s.stepLeft}>
                  <div
                    style={{
                      ...s.stepCircle,
                      background: color,
                      boxShadow: `0 0 0 4px ${color}22`,
                    }}
                  >
                    {item.step}
                  </div>
                  {!isLast && (
                    <div
                      style={{ ...s.connector, borderColor: color + "44" }}
                    />
                  )}
                </div>

                {/* Right — card */}
                <div
                  style={{ ...s.stepCard, borderLeft: `3px solid ${color}` }}
                >
                  <div style={s.stepTop}>
                    <span style={s.conceptName}>{name}</span>
                    <span
                      style={{
                        ...s.levelBadge,
                        color,
                        background: color + "18",
                        border: `1px solid ${color}44`,
                      }}
                    >
                      Level {level}
                    </span>
                  </div>
                  <div style={s.stepMeta}>
                    <span style={s.qVal}>
                      Q-value: {item.q_value.toFixed(2)}
                    </span>
                    <span
                      style={{
                        ...s.stepStatus,
                        color: i === 0 ? "#1D9E75" : "#B4B2A9",
                      }}
                    >
                      {i === 0
                        ? "● Current"
                        : i === 1
                          ? "○ Next up"
                          : `○ Step ${item.step}`}
                    </span>
                  </div>
                  {i === 0 && (
                    <button
                      style={s.startBtn}
                      onClick={() => {
                        localStorage.setItem("current_concept", item.concept);
                        navigate("/dashboard/learn");
                      }}
                    >
                      Start this concept →
                    </button>
                  )}
                </div>
              </div>
            );
          })}

          {/* Footer note */}
          <div style={s.footerNote}>
            🤖 Path generated using Q-table lookup from your mastery profile.
            Updates after each quiz.
          </div>
        </div>
      )}
    </div>
  );
}

const s = {
  page: {
    fontFamily: "'Sora', sans-serif",
    maxWidth: "720px",
    paddingBottom: "40px",
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "flex-start",
    marginBottom: "32px",
  },
  title: {
    fontSize: "1.6rem",
    fontWeight: 700,
    color: "#1D1C1A",
    letterSpacing: "-0.3px",
    marginBottom: "4px",
  },
  sub: {
    fontSize: "0.85rem",
    color: "#888780",
  },
  learnBtn: {
    padding: "10px 20px",
    borderRadius: "10px",
    background: "#1D9E75",
    color: "#fff",
    fontSize: "0.88rem",
    fontWeight: 600,
    border: "none",
    cursor: "pointer",
    fontFamily: "'Sora', sans-serif",
    flexShrink: 0,
  },
  loadWrap: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: "14px",
    padding: "80px 0",
  },
  spinner: {
    width: "36px",
    height: "36px",
    border: "3px solid #E1F5EE",
    borderTop: "3px solid #1D9E75",
    borderRadius: "50%",
    animation: "spin 0.8s linear infinite",
  },
  loadText: {
    fontSize: "0.88rem",
    color: "#888780",
  },
  errorBox: {
    background: "#FCEBEB",
    color: "#791F1F",
    padding: "14px 18px",
    borderRadius: "10px",
    fontSize: "0.88rem",
  },
  pathWrap: {
    display: "flex",
    flexDirection: "column",
  },
  stepRow: {
    display: "flex",
    gap: "20px",
    alignItems: "flex-start",
  },
  stepLeft: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    flexShrink: 0,
    width: "36px",
  },
  stepCircle: {
    width: "36px",
    height: "36px",
    borderRadius: "50%",
    color: "#fff",
    fontSize: "0.85rem",
    fontWeight: 700,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    flexShrink: 0,
    zIndex: 1,
  },
  connector: {
    width: "0",
    height: "100%",
    minHeight: "40px",
    borderLeft: "2px dashed",
    marginTop: "4px",
    marginBottom: "4px",
  },
  stepCard: {
    flex: 1,
    background: "#fff",
    border: "1px solid #EEECE6",
    borderRadius: "12px",
    padding: "16px 20px",
    marginBottom: "16px",
  },
  stepTop: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    marginBottom: "8px",
  },
  conceptName: {
    fontSize: "1rem",
    fontWeight: 600,
    color: "#1D1C1A",
  },
  levelBadge: {
    fontSize: "0.72rem",
    fontWeight: 600,
    padding: "3px 10px",
    borderRadius: "20px",
  },
  stepMeta: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "4px",
  },
  qVal: {
    fontSize: "0.75rem",
    color: "#B4B2A9",
    fontFamily: "'JetBrains Mono', monospace",
  },
  stepStatus: {
    fontSize: "0.75rem",
    fontWeight: 500,
  },
  startBtn: {
    marginTop: "12px",
    padding: "8px 16px",
    borderRadius: "8px",
    background: "#085041",
    color: "#fff",
    fontSize: "0.82rem",
    fontWeight: 600,
    border: "none",
    cursor: "pointer",
    fontFamily: "'Sora', sans-serif",
  },
  footerNote: {
    fontSize: "0.78rem",
    color: "#B4B2A9",
    background: "#F7F6F2",
    border: "1px solid #EEECE6",
    borderRadius: "10px",
    padding: "12px 16px",
    marginTop: "8px",
  },
};
